function useInView(th = 0.1) {
  const ref = useRef(null); const [v, setV] = useState(false);
  useEffect(() => { const el = ref.current; if (!el) return; const o = new IntersectionObserver(([e]) => { if (e.isIntersecting) setV(true); }, { threshold: th }); o.observe(el); return () => o.disconnect(); }, [th]);
  return [ref, v];
}
function useCounter(end, dur = 2000, start = 0, trigger = false) {
  const [v, setV] = useState(start);
  useEffect(() => { if (!trigger) return; let st = null; const step = (ts) => { if (!st) st = ts; const p = Math.min((ts - st) / dur, 1); setV(Math.floor((1 - Math.pow(1 - p, 3)) * (end - start) + start)); if (p < 1) requestAnimationFrame(step); }; requestAnimationFrame(step); }, [trigger, end, dur, start]);
  return v;
}
function R({ children, delay = 0, style = {} }) {
  const [ref, v] = useInView(0.06);
  return <div ref={ref} style={{ opacity: v ? 1 : 0, transform: v ? "none" : "translateY(36px)", transition: `opacity .8s cubic-bezier(.16,1,.3,1) ${delay}s, transform .8s cubic-bezier(.16,1,.3,1) ${delay}s`, ...style }}>{children}</div>;
}
